label("$S$",iFoot,W);
label("$I$",I,E);
draw(iFoot--I);
pair I2 = incenter(A,(3,5),B);
pair iFoot2 = foot(I2,(0,0),(3,5));
label("$T$",iFoot2,W);
label("$E$",I2,S);
draw(iFoot2--I2);
draw((3,5)--(I2));
[/asy]

